/// <reference types="vite/client" />

// Augment Vite's ImportMetaEnv with custom environment variables
interface ImportMetaEnv {
  readonly VITE_ENV: string;
}

declare module "*.svg" {
  const content: string;
  export default content;
}

declare module "*.png" {
  const content: string;
  export default content;
}

declare module "*.jpg" {
  const content: string;
  export default content;
}

declare module "*.jpeg" {
  const content: string;
  export default content;
}

declare module "*.gif" {
  const content: string;
  export default content;
}
